{
  "grammar": [
    {
      "pattern": "Verb + 來 / 去",
      "structure": ["Verb", "來/去"],
      "explanation_en": "Direction complements 來 and 去 indicate movement toward or away from the speaker. 來 means 'come (toward speaker)', 去 means 'go (away from speaker)'.",
      "title": "Direction Complements: 來 and 去",
      "meaning": "Indicates movement direction relative to the speaker",
      "when_to_use": ["When describing movement toward the speaker (來)", "When describing movement away from the speaker (去)"],
      "when_not_to_use": ["Do not use for static positions", "Do not use with verbs that don't imply movement"],
      "pragmatic_notes": "In Taiwan, 來 and 去 are commonly used in daily conversation, e.g., '你過來一下' (come here a moment).",
      "word_order_notes": "Verb + 來/去, no object between verb and complement",
      "english_contrast": "English uses 'come' and 'go' as separate verbs; Chinese attaches them as complements.",
      "korean_contrast": "Korean uses '오다/가다' as separate verbs; Chinese uses them as suffixes.",
      "negative_examples": [
        {
          "text": "我來去商店。",
          "error": "Should be '我去商店' or '我來商店' without combining 來 and 去."
        }
      ],
      "incorrect_examples": [
        {
          "text": "他走來這裡。",
          "error": "Should be '他走過來這裡' or '他來這裡' for natural flow."
        }
      ],
      "transformation_drills": ["Change '他來' to '他走來'", "Change '我去' to '我走去'"],
      "production_drills": ["Describe someone coming toward you using 來", "Describe someone going away using 去"],
      "common_error_patterns": ["Using 來 and 去 together incorrectly", "Forgetting to attach to verb"],
      "repair_feedback": {
        "word_order": "Place 來/去 immediately after the verb.",
        "politeness": "Use 請 before verb for polite requests.",
        "vocabulary": "Use movement verbs like 走, 跑, 搬."
      }
    },
    {
      "pattern": "Verb + 進來 / 進去 / 出來 / 出去",
      "structure": ["Verb", "進來/進去/出來/出去"],
      "explanation_en": "These direction complements indicate movement in/out relative to a space. 進來 = come in, 進去 = go in, 出來 = come out, 出去 = go out.",
      "title": "Direction Complements: 進 and 出",
      "meaning": "Indicates movement into or out of a space",
      "when_to_use": ["When someone enters a space (進來/進去)", "When someone exits a space (出來/出去)"],
      "when_not_to_use": ["Do not use for movement within the same space", "Do not use without a verb of motion"],
      "pragmatic_notes": "In Taiwan, '請進來' (please come in) is common at entrances; '出去' can be abrupt, so use '請出去' politely.",
      "word_order_notes": "Verb + 進來/進去/出來/出去, no object between verb and complement",
      "english_contrast": "English uses 'come in/go out' as phrasal verbs; Chinese uses verb + complement.",
      "korean_contrast": "Korean uses '들어오다/나가다' as compound verbs; Chinese uses verb + 進來/出去.",
      "negative_examples": [
        {
          "text": "他進來教室。",
          "error": "Should be '他走進教室' or '他進來教室' (but 進來 already implies movement, so verb is optional)."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我出去外面。",
          "error": "Should be '我出去' or '我到外面去' for clarity."
        }
      ],
      "transformation_drills": ["Change '他進來' to '他走進來'", "Change '我出去' to '我跑出去'"],
      "production_drills": ["Describe someone entering a room", "Describe someone leaving a building"],
      "common_error_patterns": ["Using 進來/進去 interchangeably without considering speaker position", "Adding unnecessary objects"],
      "repair_feedback": {
        "word_order": "Place 進來/進去/出來/出去 after the verb.",
        "politeness": "Use 請 for polite commands like '請進來'.",
        "vocabulary": "Use verbs like 走, 跑, 搬, 拿."
      }
    },
    {
      "pattern": "Verb + 上來 / 上去 / 下來 / 下去",
      "structure": ["Verb", "上來/上去/下來/下去"],
      "explanation_en": "These direction complements indicate movement up/down relative to the speaker. 上來 = come up, 上去 = go up, 下來 = come down, 下去 = go down.",
      "title": "Direction Complements: 上 and 下",
      "meaning": "Indicates movement upward or downward",
      "when_to_use": ["When someone moves upward (上來/上去)", "When someone moves downward (下來/下去)"],
      "when_not_to_use": ["Do not use for horizontal movement", "Do not use without a verb of motion"],
      "pragmatic_notes": "In Taiwan, '請上來' (please come up) is used when inviting someone upstairs; '下去' can mean 'go down' or 'continue' in context.",
      "word_order_notes": "Verb + 上來/上去/下來/下去, no object between verb and complement",
      "english_contrast": "English uses 'come up/go down' as phrasal verbs; Chinese uses verb + complement.",
      "korean_contrast": "Korean uses '올라오다/내려가다' as compound verbs; Chinese uses verb + 上來/下去.",
      "negative_examples": [
        {
          "text": "他上去樓上。",
          "error": "Should be '他上去' or '他到樓上去' for natural expression."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我下來下面。",
          "error": "Should be '我下來' or '我到下面來' for clarity."
        }
      ],
      "transformation_drills": ["Change '他上來' to '他走上來'", "Change '我下去' to '我跑下去'"],
      "production_drills": ["Describe someone climbing up stairs", "Describe someone going down a hill"],
      "common_error_patterns": ["Using 上來/上去 incorrectly based on speaker position", "Adding redundant location words"],
      "repair_feedback": {
        "word_order": "Place 上來/上去/下來/下去 after the verb.",
        "politeness": "Use 請 for polite requests like '請下來'.",
        "vocabulary": "Use verbs like 走, 跑, 爬, 搬."
      }
    }
  ]
}
